function upu_handle_upload() {
    if (isset($_POST['upload_files'])) {
        $upload_dir = wp_upload_dir();
        $user_dir = $upload_dir['basedir'] . '/user-files/' . get_current_user_id();
        
        if (!file_exists($user_dir)) {
            mkdir($user_dir, 0755, true);
        }

        $allowed_image_types = array('image/jpeg', 'image/png', 'image/gif');
        $allowed_doc_types = array('application/pdf', 'application/msword', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document');

        if (isset($_FILES['profile_picture']) && $_FILES['profile_picture']['error'] == 0) {
            if (in_array($_FILES['profile_picture']['type'], $allowed_image_types)) {
                move_uploaded_file($_FILES['profile_picture']['tmp_name'], $user_dir . '/profile_picture.' . pathinfo($_FILES['profile_picture']['name'], PATHINFO_EXTENSION));
            }
        }

        if (isset($_FILES['document']) && $_FILES['document']['error'] == 0) {
            if (in_array($_FILES['document']['type'], $allowed_doc_types)) {
                move_uploaded_file($_FILES['document']['tmp_name'], $user_dir . '/document.' . pathinfo($_FILES['document']['name'], PATHINFO_EXTENSION));
            }
        }
    }
}
add_action('init', 'upu_handle_upload');
